#include <bits/stdc++.h>
using namespace std;
const int maxn=2e4+10;
int n,m,a[maxn],b[maxn];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=m;i++)cin>>b[i];
    if(n>m){
        cout<<"you died!";return 0;
    }
    int i=1,j=1,sum=0;
    sort(a+1,a+n+1);sort(b+1,b+m+1);
    while(i<=n && j<=m){
        if(b[j]>=a[i]){
            i++;
            sum+=b[j++];
        }
        else j++;
    }
    if(i<=n)cout<<"you died!";
    else cout<<sum;
    return 0;
}
